"use client";

import { useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { jwtDecode } from "jwt-decode"; 

export default function LoginSuccessPage() {
  const router = useRouter();
  const searchParams = useSearchParams();

  useEffect(() => {
    // 1. URL에서 토큰 추출
    const token = searchParams.get('token');

    if (token) {
      // 2. 로컬 스토리지에 토큰 저장
      localStorage.setItem('token', token);

      // 3. 토큰 디코딩하여 userId 추출 및 저장 (기존 로그인 로직과 통일)
      try {
        const decoded: any = jwtDecode(token);
        if (decoded.userId) {
          localStorage.setItem('userId', String(decoded.userId));
          console.log("Social Login Success! UserId:", decoded.userId);
        }
      } catch (e) {
        console.error("Token decode failed", e);
      }

      // 4. 메인 페이지로 이동 (약간의 딜레이를 주어 사용자가 로그인 됨을 인지하게 할 수도 있음)
      // alert("카카오 로그인 성공!"); // (선택 사항)
      window.location.href = '/main';
    } else {
      // 토큰이 없으면 로그인 실패 처리
      alert("로그인에 실패했습니다.");
      router.replace('/main');
    }
  }, [searchParams, router]);

  return (
    <div style={{ 
      display: 'flex', 
      justifyContent: 'center', 
      alignItems: 'center', 
      height: '100vh', 
      fontSize: '18px', 
      fontWeight: 'bold' 
    }}>
      <div style={{ textAlign: 'center' }}>
        <p>로그인 처리 중입니다...</p>
        <p>잠시만 기다려주세요.</p>
      </div>
    </div>
  );
}